import org.owasp.esapi.ESAPI;
import org.owasp.esapi.codecs.HTMLEntityCodec;

import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class XSSFixedCode {

    public static void main(String[] args) throws IOException {
        BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));

        System.out.print("Enter your name: ");
        String userName = reader.readLine();

        // Properly sanitizing and encoding user input to prevent XSS
        HTMLEntityCodec codec = new HTMLEntityCodec();
        String safeUserName = codec.encodeForHTML(userName);

        System.out.println("Hello, " + safeUserName + "! Welcome to our website.");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
